INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.8.18','cb','cb.adi.8','ЧБ Ади 8.18',18,'যার যথাশক্তি ভিক্ষা সবেই সন্তোষে ।
প্রভুর ঝুলিতে দিয়া নারীগণ হাসে ॥১৮॥','йа̄’ра йатха̄-ш́акти бхикш̣а̄ сабеи сантош̣е
прабхура джхулите дийа̄ на̄рӣ-ган̣а ха̄се',NULL,NULL),('cb.adi.8.19','cb','cb.adi.8','ЧБ Ади 8.19',19,'দ্বিজপত্নীরূপ ধরি’ ব্রহ্মানী, রুদ্রাণী ।
যত পতিব্রতা মুনিবর্গের গৃহিণী ॥১৯॥','двиджа-патнӣ-рӯпа дхари’ брахма̄н̣ӣ, рудра̄н̣ӣ
йата пати-врата̄ муни-варгера гр̣хин̣ӣ',NULL,NULL),('cb.adi.8.20','cb','cb.adi.8','ЧБ Ади 8.20',20,'শ্রীবামন-রূপ প্রভুর দেখিয়া সন্তোষে ।
সবেই ঝুলিতে ভিক্ষা দিয়া দিয়া হাসে ॥২০॥','ш́рӣ-ва̄мана-рӯпа прабхура декхийа̄ сантош̣е
сабеи джхулите бхикш̣а̄ дийа̄ дийа̄ ха̄се',NULL,NULL),('cb.adi.8.21','cb','cb.adi.8','ЧБ Ади 8.21',21,'প্রভুও করেন শ্রীবামন-রূপ-লীলা ।
জীবের উদ্ধার লাগি’ এ-সকল খেলা ॥২১॥','прабхуо карена ш́рӣ-ва̄мана-рӯпа-лӣла̄
джӣвера уддха̄ра ла̄ги’ э сакала кхӣла̄',NULL,NULL),('cb.adi.8.22','cb','cb.adi.8','ЧБ Ади 8.22',22,'জয় জয় শ্রীবামনরূপ গৌরচন্দ্র ।
দান দেহ’ হৃদয়ে তোমার পদদ্বন্দ্ব ॥২২॥','джайа джайа ш́рӣ-ва̄мана-рӯпа гаурачандра
да̄на деха’ хр̣дайе тома̄ра пада-двандва',NULL,NULL),('cb.adi.8.23','cb','cb.adi.8','ЧБ Ади 8.23',23,'যে শুনে প্রভুর যজ্ঞসূত্রের গ্রহণ ।
সে পায় চৈতন্যচন্দ্র-চরণে শরণ ॥২৩॥','йе ш́уне прабхура йаджн̃а-сӯтрера грахан̣а
се па̄йа чаитанйачандра-чаран̣е ш́аран̣а',NULL,NULL),('cb.adi.8.24','cb','cb.adi.8','ЧБ Ади 8.24',24,'হেনমতে বৈকুণ্ঠনায়ক শচী-ঘরে ।
বেদের নিগূঢ় নানামত ক্রীড়া করে ॥২৪॥','хена-мате ваикун̣т̣ха-на̄йака ш́ачӣ-гхаре
ведера нигӯд̣ха н а̄на̄-мата крӣд̣а̄ каре',NULL,NULL),('cb.adi.8.25','cb','cb.adi.8','ЧБ Ади 8.25',25,'ঘরে সর্ব্বশাস্ত্রের বুঝিয়া সমীহিত ।
গোষ্ঠী-মাঝে প্রভুর পড়িতে হৈল চিত্ত ॥২৫॥','гхаре сарва-ш́а̄стрера буджхийа̄ самӣхита
гош̣т̣хи-ма̄джхе прабхура пад̣ите хаила чита',NULL,NULL),('cb.adi.8.26','cb','cb.adi.8','ЧБ Ади 8.26',26,'নবদ্বীপে আছে অধ্যাপক-শিরোমণি ।
গঙ্গাদাস-পণ্ডিত যে-হেন সান্দীপনি ॥২৬॥','навадвӣпе а̄чхе адхйа̄пака-ш́ироман̣и
ган̇га̄да̄са-пан̣д̣ита йе-хена са̄ндӣпани',NULL,NULL),('cb.adi.8.27','cb','cb.adi.8','ЧБ Ади 8.27',27,'ব্যাকরণশাস্ত্রের একান্ত তত্ত্ববিৎ ।
তাঁর ঠাঞি পড়িতে প্রভুর সমীহিত ॥২৭॥','вйа̄каран̣а-ш́а̄стрера эка̄нта таттва-вит
та̄н̇’ра т̣ха̄н̃и пад̣ите прабхура самӣхита',NULL,NULL),('cb.adi.8.28','cb','cb.adi.8','ЧБ Ади 8.28',28,'বুঝিলেন পুত্ত্রের ইঙ্গিত মিশ্রবর ।
পুত্ত্র-সঙ্গে গেলা গঙ্গাদাসদ্বিজ-ঘর ॥২৮॥','буджхилена путрера ин̇гита миш́ра-вара
путра-сан̇ге гела̄ ган̇га̄да̄са-двиджа-гхара',NULL,NULL),('cb.adi.8.29','cb','cb.adi.8','ЧБ Ади 8.29',29,'মিশ্র দেখি’ গঙ্গাদাস সম্ভ্রমে উঠিলা ।
আলিঙ্গন করি’ এক আসনে বসিলা ॥২৯॥','миш́ра декхи’ ган̇га̄да̄са самбхраме ут̣хила̄
а̄лин̇гана кари’ эка а̄сане васила̄',NULL,NULL),('cb.adi.8.30','cb','cb.adi.8','ЧБ Ади 8.30',30,'মিশ্র বোলে,—“পুত্ত্র আমি দিলুঁ তোমা’ স্থানে ।
পড়াইবা শুনাইবা সকল আপনে” ॥৩০॥','миш́ра боле, — ‘путра а̄ми дилун̇ тома̄’ стха̄не
пад̣а̄иба̄ ш́уна̄иба̄ сакала а̄пане’',NULL,NULL),('cb.adi.8.31','cb','cb.adi.8','ЧБ Ади 8.31',31,'গঙ্গাদাস বোলে,—“বড় ভাগ্য সে আমার ।
পড়াইমু যত শক্তি আছয়ে আমার” ॥৩১॥','ган̇га̄да̄са боле, — ‘бад̣а бха̄гйа се а̄ма̄ра
пад̣а̄иму йата ш́акти а̄чхайе а̄ма̄ра’',NULL,NULL),('cb.adi.8.32','cb','cb.adi.8','ЧБ Ади 8.32',32,'শিষ্য দেখি’ পরম-আনন্দে গঙ্গাদাস ।
পুত্ত্রপ্রায় করিয়া রাখিলা নিজ-পাশ ॥৩২॥','ш́иш̣йа декхи’ парама-а̄нанде ган̇га̄да̄са
путра-пра̄йа карийа̄ ра̄кхила̄ ниджа-па̄ш́а',NULL,NULL),('cb.adi.8.33','cb','cb.adi.8','ЧБ Ади 8.33',33,'যত ব্যাখ্যা গঙ্গাদাস পণ্ডিত করেন ।
সকৃৎ শুনিলে মাত্র ঠাকুর ধরেন ॥৩৩॥','йата вйа̄кхйа̄ ган̇га̄да̄са пан̣д̣ита карена
сакр̣т ш́униле ма̄тра т̣ха̄кура дхарена',NULL,NULL),('cb.adi.8.34','cb','cb.adi.8','ЧБ Ади 8.34',34,'গুরুর যতেক ব্যাখ্যা করেন খন ।
পূনর্ব্বার সেই ব্যাখ্যা করেন স্থাপন ॥৩৪॥','гурура йатека вйа̄кхйа̄ карена кхан̣д̣ана
пунар-ба̄ра сеи вйа̄кхйа̄ карена стха̄пана',NULL,NULL),('cb.adi.8.35','cb','cb.adi.8','ЧБ Ади 8.35',35,'সহস্র সহস্র শিষ্য পড়ে যত জন ।
হেন কারো শক্তি নাহি দিবারে দূষণ ॥৩৫॥','сахасра сахасра ш́иш̣йа пад̣е йата джана
хена ка̄ро ш́акти на̄хи дива̄ре дӯш̣ан̣а',NULL,NULL),('cb.adi.8.36','cb','cb.adi.8','ЧБ Ади 8.36',36,'দেখিয়া অদ্ভুত বুদ্ধি গুরু হরষিত ।
সর্ব্বশিষ্যশ্রেষ্ঠ করি’ করিলা পূজিত ॥৩৬॥','декхийа̄ адбхута буддхи гуру хараш̣ита
сарва-ш́иш̣йа-ш́рӣш̣т̣ха кари’ карила̄ пӯджита',NULL,NULL),('cb.adi.8.37','cb','cb.adi.8','ЧБ Ади 8.37',37,'যত পড়ে গঙ্গাদাস-পণ্ডিতের স্থানে ।
সবারেই ঠাকুর চালেন অনুক্ষণে ॥৩৭॥','йата пад̣е ган̇га̄да̄са-пан̣д̣итера стха̄не
саба̄реи т̣ха̄кура ча̄лена анукш̣ане',NULL,NULL),('cb.adi.8.38','cb','cb.adi.8','ЧБ Ади 8.38',38,'শ্রীমুরারি গুপ্ত, শ্রীকমলাকান্ত-নাম ।
কৃষ্ণানন্দ-আদি যত গোষ্ঠীর প্রধান ॥৩৮॥','ш́рӣ-мура̄ри гупта, ш́рӣ-камала̄ка̄нта-на̄ма
кр̣ш̣н̣а̄нанда-а̄ди йата гош̣т̣хӣра прадха̄на',NULL,NULL),('cb.adi.8.39','cb','cb.adi.8','ЧБ Ади 8.39',39,'সবারে চালয়ে প্রভু ফাঁকি জিজ্ঞাসিয়া ।
শিশুজ্ঞানে কেহ কিছু না বোলে হাসিয়া ॥৩৯॥','саба̄ре ча̄лайе прабху пхан̇ки джиджн̃а̄сийа̄
ш́иш́у-джн̃а̄не кеха кичху на̄ боле ха̄сийа̄',NULL,NULL),('cb.adi.8.40','cb','cb.adi.8','ЧБ Ади 8.40',40,'এইমত প্রতিদিন পড়িয়া শুনিয়া ।
গঙ্গাস্নানে চলে নিজ-বয়স্য লইয়া ॥৪০॥','эи-мата прати-дина пад̣ийа̄ ш́унийа̄
ган̇га̄-сна̄не чале ниджа-вайасйа лаийа̄',NULL,NULL),('cb.adi.8.41','cb','cb.adi.8','ЧБ Ади 8.41',41,'পড়ুয়ার অন্ত নাহি নবদ্বীপ-পুরে ।
পড়িয়া মধ্যাহ্নে সবে গঙ্গাস্নান করে ॥৪১॥','пад̣уйа̄ра анта на̄хи навадвӣпа-пурӣ
пад̣ийа̄ мадхйа̄хне сабе ган̇га̄-сна̄на каре',NULL,NULL),('cb.adi.8.42','cb','cb.adi.8','ЧБ Ади 8.42',42,'একো অধ্যাপকের সহস্র শিষ্যগণ ।
অন্যোঽন্যে কলহ করেন অনুক্ষণ ॥৪২॥','эко адхйа̄пакера сахасра ш́иш̣йа-ган̣а
анйо ’нйе калаха карена анукш̣ан̣а',NULL,NULL),('cb.adi.8.43','cb','cb.adi.8','ЧБ Ади 8.43',43,'প্রথম বয়স প্রভু স্বভাব-চঞ্চল ।
পড়ুয়াগণের সহ করেন কোন্দল ॥৪৩॥','пратхама вайаса прабху свабха̄ва-чан̃чала
пад̣уйа̄-ган̣ера саха карена кондала',NULL,NULL),('cb.adi.8.44','cb','cb.adi.8','ЧБ Ади 8.44',44,'কেহ বোলে,—“তোর গুরু কোন্ বুদ্ধি তা’র” ।
কেহ বোলে,—“এই দেখ, আমি শিষ্য যা’র” ॥৪৪॥','кеха боле, — ‘тора гуру кон буддхи та̄’ра’
кеха боле, — ‘еи декха, а̄ми ш́иш̣йа йа̄’ра’',NULL,NULL),('cb.adi.8.45','cb','cb.adi.8','ЧБ Ади 8.45',45,'এইমত অল্পে-অল্পে হয় গালাগালি ।
তবে জল-ফেলাফেলি, তবে দেয় বালি ॥৪৫॥','эи-мата алпе алпе хайа га̄ла̄га̄ли
табе джала-пхела̄пхели, табе дейа ба̄ли',NULL,NULL),('cb.adi.8.46','cb','cb.adi.8','ЧБ Ади 8.46',46,'তবে হয় মারামারি, যে যাহারে পারে ।
কর্দ্দম ফেলিয়া কারো গা’য়ে কেহ মারে ॥৪৬॥','табе хайа ма̄ра̄ма̄ри, йе йа̄ха̄ре па̄ре
кардама пхелийа̄ ка̄’ро га̄йе кеха ма̄ре',NULL,NULL),('cb.adi.8.47','cb','cb.adi.8','ЧБ Ади 8.47',47,'রাজার দোহাই দিয়া কেহ কারে ধরে ।
মারিয়া পলায় কেহ গঙ্গার ওপারে ॥৪৭॥','ра̄джа̄ра доха̄и дийа̄ кеха ка̄’ре дхаре
ма̄рийа̄ пала̄йа кеха ган̇га̄ра упа̄ре',NULL,NULL),('cb.adi.8.48','cb','cb.adi.8','ЧБ Ади 8.48',48,'এত হুড়াহুড়ি করে পড়ুয়া-সকল ।
বালি-কাদাময় সব হয় গঙ্গাজল ॥৪৮॥','эта худ̣а̄худ̣и каре пад̣уйа̄-сакала
ба̄ли-ка̄да̄майа саба хайа ган̇га̄-джала',NULL,NULL),('cb.adi.8.49','cb','cb.adi.8','ЧБ Ади 8.49',49,'জল ভরিবারে নাহি পারে নারীগণ ।
না পারে করিতে স্নান ব্রাহ্মণ সজ্জন ॥৪৯॥','джала бхариба̄ре на̄хи па̄ре на̄рӣ-ган̣а
на̄ па̄ре карите сна̄на бра̄хман̣а саджджана',NULL,NULL),('cb.adi.8.50','cb','cb.adi.8','ЧБ Ади 8.50',50,'পরম-চঞ্চল প্রভু বিশ্বম্ভর-রায় ।
এইমত প্রভু প্রতি-ঘাটে ঘাটে যায় ॥৫০॥','парама-чан̃чала прабху виш́вамбхара-ра̄йа
эи-мата прабху прати-гха̄т̣е-гха̄т̣е йа̄йа',NULL,NULL),('cb.adi.8.51','cb','cb.adi.8','ЧБ Ади 8.51',51,'প্রতিঘাটে পড়ুয়ার অন্ত নাহি পাই ।
ঠাকুর কলহ করে প্রতি-ঠাঞি ঠাঞি ॥৫১॥','прати-гха̄т̣е пад̣уйа̄ра анта на̄хи па̄и
т̣ха̄кура калаха каре прати т̣ха̄н̃и т̣ха̄н̃и',NULL,NULL),('cb.adi.8.52','cb','cb.adi.8','ЧБ Ади 8.52',52,'প্রতিঘাটে যায় প্রভু গঙ্গায় সাঁতারি’ ।
একো ঘাটে দুই চারি দণ্ড ক্রীড়া করি’ ॥৫২॥','прати-гха̄т̣е йа̄йа прабху ган̇га̄йа са̄н̇та̄ри’
эко гха̄т̣е дуи ча̄ри дан̣д̣а крӣд̣а̄ кари’',NULL,NULL),('cb.adi.8.53','cb','cb.adi.8','ЧБ Ади 8.53',53,'যত যত প্রামাণিক পড়ুয়ার গণ ।
তারা বোলে,—“কলহ করহ কি কারণ ?” ॥৫৩॥','йата йата пра̄ма̄н̣ика пад̣уйа̄ра ган̣а
та̄’ра̄ боле, — ‘калаха караха ки ка̄ран̣а?’',NULL,NULL),('cb.adi.8.54','cb','cb.adi.8','ЧБ Ади 8.54',54,'জিজ্ঞাসা করহ,—“বুঝি, কার কো বুদ্ধি ।
বৃত্তি-পঞ্জি-টীকার, কে জানে, দেখি, শুদ্ধি” ॥৫৪॥','джиджн̃а̄са̄ караха, — ‘буджхи, ка̄’ра кон буддхи!
вр̣тти-пан̃джи-т̣ӣка̄ра, ке джа̄не, декхи, ш́уддхи’',NULL,NULL),('cb.adi.8.55','cb','cb.adi.8','ЧБ Ади 8.55',55,'প্রভু বোলে,—“ভাল ভাল, এই কথা হয় ।
জিজ্ঞাসুক আমারে যাহার চিত্তে লয়” ॥৫৫॥','прабху боле, — ‘бха̄ла бха̄ла, эи катха̄ хайа
джиджн̃а̄сука а̄ма̄ре йа̄ха̄ра читте лайа’',NULL,NULL),('cb.adi.8.56','cb','cb.adi.8','ЧБ Ади 8.56',56,'কেহ বোলে,—“এত কেনে কর অহঙ্কার ?” ।
প্রভু বোলে,—“জিজ্ঞাসহ যে চিত্তে তোমার” ॥৫৬॥','кеха боле,—‘ета кене кара ахан̇ка̄ра?’
